glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 uPrimary;
uniform vec3 uSecondary;
uniform vec3 uGlow;
uniform vec3 uAnchor;
uniform float uTimeScale;
uniform float uTime;

float ring(vec2 p,float r,float w){
 float d=abs(length(p)-r);
 return 1.0-smoothstep(w,w+0.012,d);
}

float arcMask(vec2 p,float a0,float a1){
 float a=atan(p.y,p.x);
 a = a < 0.0 ? a + 6.28318530718 : a;
 float m0=smoothstep(a0,a0+0.08,a);
 float m1=1.0-smoothstep(a1-0.08,a1,a);
 return m0*m1;
}

float softDisc(vec2 p,float r){
 return 1.0-smoothstep(r,r+0.02,length(p));
}

void main(){
 vec2 uv=vUv*2.0-1.0;
 uv.y*=1.25;
 float t=uTime*uTimeScale;
 vec3 col=vec3(0.95,0.93,0.88);

 float paper=0.035*sin(uv.x*11.0+uv.y*7.0)+0.02*sin(uv.x*23.0-uv.y*19.0);
 col += paper;

 vec2 p1=uv-vec2(-0.16+0.012*sin(t*0.7),0.08);
 vec2 p2=uv-vec2(0.17+0.01*cos(t*0.6),-0.02);
 float a1=ring(p1,0.58,0.025)*arcMask(p1,0.35,4.95);
 float a2=ring(p2,0.52,0.03)*arcMask(p2,1.15,5.95);
 float core=softDisc(uv-vec2(0.02,0.36+0.01*sin(t)),0.09);
 float miss=softDisc(uv-vec2(0.12,0.32),0.05);
 float veil=smoothstep(0.95,0.15,abs(uv.x*0.72+uv.y*0.24));

 col = mix(col,uPrimary,a1*0.82);
 col = mix(col,uSecondary,a2*0.84);
 col = mix(col,uGlow,core*0.88);
 col = mix(col,uAnchor,miss*0.72);
 col += 0.06*veil*uGlow;

 float grain=fract(sin(dot(floor(vUv*512.0),vec2(127.1,311.7)))*43758.5453123);
 col += (grain-0.5)*0.04;

 gl_FragColor=vec4(col,0.88);
}
